// Dependency injection example:
export class OrderService {
  // Depends on abstractions (interfaces), not concretions
  constructor(
    private orderRepo: OrderRepository,
    private productRepo: ProductRepository,
    private paymentGateway: PaymentGateway
  ) {}
  async placeOrder(userId: number, items: OrderItemInput[]): Promise<Order> {
    // Business logic: validate stock, calculate total, process payment
    for (const item of items) {
      const product = await this.productRepo.findById(item.productId);
      if (!product || product.stock < item.quantity) {
        throw new Error(`Insufficient stock for product ${item.productId}`);
      }
    }
    const total = await this.calculateTotal(items);
    await this.paymentGateway.charge(userId, total);
    return this.orderRepo.create(userId, items);
  }
}
